mapper.select:
SELECT * FROM news_article t1
                  JOIN (SELECT id FROM news_article ORDER BY publish_time DESC, id DESC LIMIT #{offset}, #{size}) t2
                       ON t1.id = t2.id;

SELECT id, title, summary, source, author, publish_time, create_time
FROM news_article
WHERE publish_time < #{lastArticle.publishTime}
   OR (publish_time = #{lastArticle.publishTime} AND id < #{lastArticle.id})
ORDER BY publish_time DESC, id DESC
LIMIT #{size}

SELECT * FROM (
    SELECT id, title, summary, source, author, publish_time, create_time
    FROM news_article
    WHERE publish_time > #{startArticle.publishTime}
       OR (publish_time = #{startArticle.publishTime} AND id > #{startArticle.id})
    ORDER BY publish_time ASC, id ASC
    LIMIT #{size}
) AS tmp
ORDER BY publish_time DESC, id DESC
